import React, { useEffect, useState } from "react";
import API from "../api/api";

function CustomerDashboard() {
  const [schedules, setSchedules] = useState([]);

  useEffect(() => {
    API.get("/customer/schedules/12?stop_id=56")
      .then((res) => setSchedules(res.data.next_trips))
      .catch((err) => console.log(err));
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-2">Next Trips</h2>
      <ul>
        {schedules.map((trip) => (
          <li key={trip.id}>
            Trip {trip.id}: {trip.start_time} - {trip.end_time}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default CustomerDashboard;
